/**
 * Inline DejaVu Sans subset for jsPDF Vietnamese rendering.
 * Source: public/legacy.html:3410-3411 (font base64) + 3413-3420 (loadVNFont).
 *
 * Importing this module adds ~167 KB to the chunk that consumes it. The exports
 * are kept in a dedicated module so non-PDF code paths never pull them in.
 */
import type { jsPDF } from "jspdf";

export const VN_FONT_REGULAR = "";

export const VN_FONT_BOLD = "";

/**
 * Register DejaVu Sans (regular + bold) on the given jsPDF instance.
 * Returns true if registration succeeded so callers can set FONT = "DejaVu",
 * else they should fall back to Helvetica + ASCII-stripped text.
 * Source: legacy.html:3413-3420.
 */
export function loadVNFont(pdf: jsPDF): boolean {
  try {
    pdf.addFileToVFS("DejaVu.ttf", VN_FONT_REGULAR);
    pdf.addFont("DejaVu.ttf", "DejaVu", "normal");
    pdf.addFileToVFS("DejaVu-Bold.ttf", VN_FONT_BOLD);
    pdf.addFont("DejaVu-Bold.ttf", "DejaVu", "bold");
    return true;
  } catch {
    return false;
  }
}
